  ('elementary-c5fb3965-moex-00109', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '關於戶口清查，下列敘述何者錯誤？', '["戶口清查之區域及期間與戶口清查日，均由直轄市、縣（市）政府訂定，並報中央主管機關備查", "戶口清查應以戶為單位，並依村（里）鄰及門牌號碼編組", "戶政事務所人員應自戶口清查日按戶查口，填寫戶口清查表", "戶政事務所完成戶口清查後，還須派員進行複查，始可辦理戶籍登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL)
